 1	import * as React from 'react';
 2	import { kialiStyle } from 'styles/StyleUtils';
 3	import { PFColors } from '../Pf/PfColors';
 4	import {
 5	  Button,
 6	  ButtonVariant,
 7	  EmptyState,
 8	  EmptyStateBody,
 9	  EmptyStateIcon,
10	  EmptyStateHeader
11	} from '@patternfly/react-core';
12	import { KialiIcon } from 'config/KialiIcon';
13	import { Outlet } from 'react-router-dom-v5-compat';
14	import { t } from 'utils/I18nUtils';
15	import { pathRoutes } from 'routes';
16	import { router } from 'app/History';
17	import { MASTHEAD_HEIGHT } from './Navigation';
18	
19	const containerStyle = kialiStyle({ marginLeft: 0, marginRight: 0 });
20	const containerPadding = kialiStyle({ padding: '0 20px 0 20px' });
21	const containerGray = kialiStyle({ background: PFColors.BackgroundColor200, height: '100%' });
22	const containerError = kialiStyle({ height: `calc(100vh - ${MASTHEAD_HEIGHT})` });
23	
24	// Add error boundary element to every path route
25	pathRoutes.forEach(route => {
26	  route.errorElement = (
27	    <EmptyState className={containerError} variant="lg">
28	      <EmptyStateHeader
29	        titleText={t('Something went wrong')}
30	        icon={<EmptyStateIcon icon={KialiIcon.Error} />}
31	        headingLevel="h1"
32	      />
33	      <EmptyStateBody>
34	        <p style={{ marginBottom: 'var(--pf-t--global--spacer--400)' }}>
35	          {t('Sorry, there was a problem. Try a refresh or navigate to a different page.')}
36	        </p>
37	        <Button
38	          variant={ButtonVariant.primary}
39	          onClick={() => {
40	            router.navigate(-1);
41	          }}
42	        >
43	          {t('Return to last page')}
44	        </Button>
45	      </EmptyStateBody>
46	    </EmptyState>
47	  );
48	});
49	
50	export const RenderPage: React.FC<{ isGraph: boolean }> = ({ isGraph }) => {
51	  return (
52	    <div className={`${containerStyle} ${isGraph ? containerPadding : containerGray}`}>
53	      <Outlet />
54	    </div>
55	  );
56	};

