 1	import * as React from 'react';
 2	import { mount } from 'enzyme';
 3	import { NavigationComponent } from '../Navigation';
 4	import { ExternalServiceInfo } from '../../../types/StatusState';
 5	import { RouterProvider, createMemoryRouter } from 'react-router-dom-v5-compat';
 6	import { pathRoutes } from 'routes';
 7	import { Provider } from 'react-redux';
 8	import { store } from 'store/ConfigStore';
 9	import { LoginActions } from 'actions/LoginActions';
10	
11	const session = {
12	  expiresOn: '2018-05-29 21:51:40.186179601 +0200 CEST m=+36039.431579761',
13	  username: 'admin'
14	};
15	
16	const externalServicesInfo: ExternalServiceInfo[] = [];
17	
18	const router = createMemoryRouter([
19	  {
20	    element: (
21	      <NavigationComponent
22	        navCollapsed={false}
23	        setNavCollapsed={() => {}}
24	        tracingUrl={''}
25	        externalServices={externalServicesInfo}
26	      />
27	    ),
28	    children: pathRoutes
29	  }
30	]);
31	
32	describe('RenderPage isGraph prop', () => {
33	  it('be sure that RenderPage isGraph is true', () => {
34	    // we need a user session to render the navigation component
35	    store.dispatch(LoginActions.loginSuccess(session));
36	
37	    router.navigate('/graph/namespaces');
38	
39	    const wrapper = mount(
40	      <Provider store={store}>
41	        <RouterProvider router={router} />
42	      </Provider>
43	    );
44	
45	    expect(wrapper.find('RenderPage').prop('isGraph')).toEqual(true);
46	  });
47	
48	  it('be sure that RenderPage isGraph is false in other pages', () => {
49	    // we need a user session to render the navigation component
50	    store.dispatch(LoginActions.loginSuccess(session));
51	
52	    router.navigate('/overview');
53	
54	    const wrapper = mount(
55	      <Provider store={store}>
56	        <RouterProvider router={router} />
57	      </Provider>
58	    );
59	
60	    expect(wrapper.find('RenderPage').prop('isGraph')).toEqual(false);
61	  });
62	});

